import json

# Get NASDAQ Capital Market symbols from storage
result_path = var_functions.query_db:30

if isinstance(result_path, str):
    with open(result_path, 'r') as f:
        nasdaq_cap_data = json.load(f)
else:
    nasdaq_cap_data = result_path

# Extract symbols and create company name mapping
nasdaq_cap_symbols = []
company_names = {}
for item in nasdaq_cap_data:
    if isinstance(item, dict) and 'Symbol' in item:
        symbol = item['Symbol']
        nasdaq_cap_symbols.append(symbol)
        company_names[symbol] = item.get('Company Description', '' )

print('__RESULT__:')
print(json.dumps({
    'total_symbols': len(nasdaq_cap_symbols),
    'sample_symbols': nasdaq_cap_symbols[:5],
    'company_names_sample': {k: company_names[k] for k in list(company_names.keys())[:3]}
}))

